parameters.jsCode:
// Takes the text found by the PDF extractor
return {
  json: {
    final_resume_text: $input.item.json.text
  }
};

// Takes the text found by Gemini Vision
return {
  json: {
    final_resume_text: $input.item.json.content.parts[0].text
  }
};

// 1. Get raw text from the AI Agent node
let aiText = $input.first().json.output || $input.first().json.response;

// 2. GET USER DATA FROM WEBHOOK
const submittedName = $('Webhook').first().json.body.name || "Unknown Candidate";
const submittedEmail = $('Webhook').first().json.body.email || "No Email";
const submittedPhone = $('Webhook').first().json.body.phone || "No Phone";

// 3. Extract JSON boundaries
const firstBrace = aiText.indexOf('{');
const lastBrace = aiText.lastIndexOf('}');

// ERROR HANDLING
if (firstBrace === -1 || lastBrace === -1) {
  return {
    "Contact_Info": `• Name: ${submittedName}\n• Email: ${submittedEmail}\n• Phone: ${submittedPhone}`,
    "Hiring_Score": 0,
    "Recommendation": "Error",
    "Insights": "• AI failed to produce valid JSON",
    "Feedback": ""
  };
}

// 4. Parse AI Data
let cleanJson = aiText.substring(firstBrace, lastBrace + 1);
let aiData = {};

try {
  aiData = JSON.parse(cleanJson.replace(/[\u0000-\u001F\u007F-\u009F]/g, ""));
} catch (e) {
    // FALLBACK: Manual extraction
    const scoreMatch = cleanJson.match(/"hiring_score"\s*:\s*"?(\d+)"?/);
    const recMatch = cleanJson.match(/"recommendation"\s*:\s*"([^"]+)"/);
    const feedbackMatch = cleanJson.match(/"email_feedback"\s*:\s*"([^"]+)"/);

    const insightSection = cleanJson.match(/"key_insights"\s*:\s*\[([\s\S]*?)\]/);
    let extractedInsights = [];
    if (insightSection && insightSection[1]) {
        extractedInsights = insightSection[1]
            .split(/","|",\s*"/)
            .map(item => item.replace(/[\[\]"']/g, "").trim())
            .filter(item => item.length > 3);
    }

    aiData = {
        hiring_score: scoreMatch ? scoreMatch[1] : 0,
        recommendation: recMatch ? recMatch[1] : "Review Required",
        key_insights: extractedInsights.length > 0 ? extractedInsights : ["Could not format insights automatically"],
        email_feedback: feedbackMatch ? feedbackMatch[1] : ""
    };
}

// 5. Format Insights
let rawInsights = aiData.key_insights || aiData.insights || [];
let formattedInsights = "";
if (Array.isArray(rawInsights)) {
    formattedInsights = rawInsights.map(i => `• ${i}`).join('\n');
} else {
    formattedInsights = rawInsights.split('. ').map(i => `• ${i.trim()}`).join('\n');
}

// 6. CREATE THE "CONTACT INFO" BLOCK
const formattedContactInfo = `• Name: ${submittedName}\n• Email: ${submittedEmail}\n• Phone: ${submittedPhone}`;


// --- INTELLIGENT FEEDBACK FIX ---
let finalScore = parseInt(aiData.hiring_score) || 0;
let finalRecommendation = aiData.recommendation || "Review";
let finalFeedback = aiData.email_feedback || "";

// If score is less than 45, FORCE REJECT
if (finalScore < 45) {
    finalRecommendation = "Reject";

    // Check if AI provided good feedback. If not, generate it from the "Gap Insight".
    if (!finalFeedback || finalFeedback.length < 5) {

        let gapInsight = "";
        // Try to grab the last insight (usually the gap/missing skill)
        if (Array.isArray(rawInsights) && rawInsights.length > 0) {
             gapInsight = rawInsights[rawInsights.length - 1]; 
        }

        if (gapInsight && gapInsight.length > 5) {
             // 1. Remove parentheses (e.g., "(Basic level)")
             let cleanGap = gapInsight.replace(/[()]/g, '');

             // 2. CRITICAL FIX: Remove negative prefixes like "Lack of", "No", "Missing"
             // This turns "Lack of Python" into just "Python"
             cleanGap = cleanGap.replace(/^(Lack of|No|Missing|Limited|Gap in)\s+/i, '');

             // 3. Construct the clean sentence
             finalFeedback = `While your background is impressive, we are currently prioritizing candidates with stronger experience in ${cleanGap}.`;
        } else {
             finalFeedback = "At this time, we are seeking candidates whose specific technical experience more closely aligns with the immediate requirements of our current projects.";
        }
    }
}
// ----------------------------------


// 7. RETURN FINAL DATA
return {
  "Contact_Info": formattedContactInfo,
  "Hiring_Score": finalScore,
  "Recommendation": finalRecommendation,
  "Insights": formattedInsights,
  "Feedback": finalFeedback 
};

for (const item of items) {
  if (item.binary && item.binary.data) {
    // This forces the system to see it as a PNG image
    item.binary.data.fileName = 'resume.png';
    item.binary.data.fileExtension = 'png';
    item.binary.data.mimeType = 'image/png';
  }
}
return items;
